 *
 * DIAGNOSTIC TOOL: This service helps identify event loop blocking
 * that causes Bull queue processing delays.
 */
@Injectable()
export class EventLoopMonitorService implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(EventLoopMonitorService.name);
  private monitorInterval: NodeJS.Timeout | null = null;
  private lastCheck: number = Date.now();

  // Log if event loop is blocked for more than this threshold
  private readonly LAG_THRESHOLD_MS = 100; // 100ms
  private readonly CHECK_INTERVAL_MS = 50; // Check every 50ms

  onModuleInit() {
    // Only enable in development/test environments
    if (process.env.NODE_ENV === "production") {
      return;
    }

    this.logger.log("🔍 Event loop monitor ENABLED (non-production mode)");
    this.lastCheck = Date.now();

    this.monitorInterval = setInterval(() => {
      const now = Date.now();
      const lag = now - this.lastCheck - this.CHECK_INTERVAL_MS;
      if (lag > this.LAG_THRESHOLD_MS) {
        this.logger.warn(
          `⚠️ EVENT LOOP BLOCKED for ${lag}ms! (expected ${this.CHECK_INTERVAL_MS}ms interval, actual ${now - this.lastCheck}ms)`,
        );
      }
      this.lastCheck = now;
    }, this.CHECK_INTERVAL_MS);

    // Ensure the interval doesn't prevent process exit
    this.monitorInterval.unref();
  }

