/**
 * Safe JSON parsing helpers for JSONB fields from raw queries
 * These handle cases where Prisma returns strings, objects, or unknown types
 */

/**
 * Safely parse a JSONB array from $queryRaw results
 * @param value - The value from Prisma (can be JsonValue, string, or unknown)
 * @returns Parsed array or empty array if parsing fails
 */
function safeParseJsonArray<T = unknown>(
  value: Prisma.JsonValue | unknown,
): T[] {
  try {
    // Already an array - return it
    if (Array.isArray(value)) {
      return value as T[];
    }

    // String - try to parse
    if (typeof value === "string") {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? (parsed as T[]) : [];
    }

    // Null or undefined - return empty array
    if (value === null || value === undefined) {
      return [];
    }

    // Object but not array - not valid for array parsing
    return [];
  } catch (error) {
    // JSON parse failed - return em

