private async formatAsExcel(data: any): Promise<Buffer> {
  const workbook = new ExcelJS.Workbook();

  // Add summary sheet
  const summarySheet = workbook.addWorksheet("Summary");
  this.addSummaryToSheet(summarySheet, data);

  // Add details sheet if available
  if (data.details || data.transactionSummaries) {
    const detailsSheet = workbook.addWorksheet("Details");
    this.addDetailsToSheet(
      detailsSheet,
      data.details || data.transactionSummaries,
    );
  }

  // Add aggregations sheet if available
  if (data.aggregations) {
    const aggregationsSheet = workbook.addWorksheet("Aggregations");
    this.addAggregationsToSheet(aggregationsSheet, data.aggregations);
  }

  // Generate buffer
  // Generate buffer - ExcelJS writeBuffer returns Uint8Array, convert to Node.js Buffer
  const uint8Array = await workbook.xlsx.writeBuffer();
  return Buffer.from(uint8Array);
}

