@Injectable()
export class DeviceSyncLogService extends DeviceSyncLogServiceBase {
  constructor(protected readonly prisma: PrismaService) {
    super(prisma);
  }

  /**
   * Executes a function and logs its execution in DeviceSyncLog for traceability.
   * @param fn - The function to execute (can be async or sync).
   * @param deviceName - The name of the device.
   * @param syncType - The type of sync operation.
   * @returns The result of the executed function.
   */
  async executeWithDeviceSyncLog<T>(
    fn: () => Promise<T> | T,
    deviceName: string,
    syncType: string,
  ): Promise<T> {
    const log = await this.prisma.deviceSyncLog.create({
      data: {
        deviceName,
        syncType,
        status: EnumDeviceSyncLogStatus.Initiated,
      },
    });

    try {
      const result: T = await fn();
      await this.prisma.deviceSyncLog.update({
        where: { id: log.id },
        data: {
          status: EnumDeviceSyncLogStatus.Complete,
          completedAt: new Date(),
        },
      });
      return result;
    } catch (error) {
      await this.prisma.deviceSyncLog.update({
        where: { id: log.id },
        data: {
          status: EnumDeviceSyncLogStatus.Failed,
          completedAt: new Date(),
        },
      });
      throw error;
    }
  }
}

