interface CommitData {
  sha: string;
  commit: {
    message: string;
  };
  html_url?: string;
}

function isCommitDataArray(value: unknown): value is CommitData[] {
  if (!Array.isArray(value)) return false;
  return value.every(
    (item) =>
      typeof item === "object" &&
      item !== null &&
      "commit" in item &&
      typeof item.commit === "object" &&
      item.commit !== null &&
      "message" in item.commit &&
      typeof item.commit.message === "string",
  );
}

