   */
  private mapInventoryDirectionToFinancial(
    direction: InventoryDirection,
  ): EnumFinancialDirection {
    switch (direction) {
      case InventoryDirection.IN:
        return EnumFinancialDirection.IN;
      case InventoryDirection.OUT:
        return EnumFinancialDirection.OUT;
      default:
        throw new BadRequestException(
          `Unknown inventory direction: ${direction}`,
        );
