// Helper function to expand alphabetic range to array (exported for reuse)
export function expandAlphabeticRange(range: [string, string]): string[] {
  const [start, end] = range;
  const startCode = start.codePointAt(0) ?? 0;
  const endCode = end.codePointAt(0) ?? 0;
  return Array.from({ length: endCode - startCode + 1 }, (_, i) =>
    String.fromCodePoint(startCode + i),
  );
}

// Helper function to convert database count to alphabetic range
// e.g., ricks: 3 becomes ["A", "C"] (A, B, C)
export function convertCountToAlphabeticRange(
  count: number | null,
): [string, string] {
  if (!count || count < 1) {
    return ["A", "A"]; // Default to single rick A
  }
  const endLetter = String.fromCodePoint(
    ("A".codePointAt(0) ?? 65) + count - 1,
  );
  return ["A", endLetter];
}

// Helper function to convert database count to numeric range
// e.g., floors: 7 becomes [1, 7]
export function convertCountToNumericRange(
  count: number | null,
): [number, number] {
  if (!count || count < 1) {
    return [1, 1]; // Default to single unit
  }
  return [1, count];
}

