  const allowedLevels = ["fatal", "error", "warn", "info", "debug", "trace"];

  if (!allowedLevels.includes(logLevel)) {
    throw new Error(
      `${logLevel} is not a valid log level. Check your LOG_LEVEL env variable.`,
