    (issue) => issue.errorLevel === EnumDeviceSyncErrorLevel.CRITICAL,
  );

  // CRITICAL issues can be approved if a resolution option is provided
  // This allows BAD_QR/NOLABEL workflows to proceed with resolution
  if (criticalIssues.length > 0 && !resolutionKey) {
    throw new BadRequestException(
      `Staging record ${stagingId} has ${criticalIssues.length} critical issue(s) and cannot be approved without a resolution option. Please select a resolution strategy.`,
    );
  }

  await this.commitStagingRecord(stagingId, reviewedBy, resolutionKey, additionalFields);

  // Update job stats after committing record
  await this.prisma.$transaction(async (tx) => {
    await this.updateJobStatsInTransaction(stagingRecord.warehouseJobId, tx);
  });
}

/**
 * Rejects a single staging record without committing changes
 */
async rejectSingleRecord(
  stagingId: string,
  reviewedBy: string,
  rejectionReason: string,
): Promise<void> {
  this.logger.log(`Rejecting single staging record ${stagingId}`);

  await this.prisma.inventoryCheckStaging.update({
    where: { id: stagingId },
    data: {
      processingStatus: InventoryCheckStagingStatus.REJECTED,
      reviewedBy,
      reviewedAt: new Date(),
      approvalDecision: ApprovalDecision.REJECTED,
      rejectionReason,
    },
  });
}

