export class BarrelAggregatesService {
  constructor(private readonly prisma: PrismaService) {}

  /**
   * Get barrel counts grouped by barrel size.
   * Uses Prisma groupBy for simple, efficient aggregation.
   *
   * @param where - Prisma where clause for filtering barrels
   * @param customerCode - Optional customer code (globalId) to filter by active owner
   * @param user - Authenticated user for authorization validation
   * @returns Array of barrel size counts, ordered by count descending
   * @throws ForbiddenException if non-privileged user queries without customer scoping
   */
  async getBarrelCountBySize(
    where: Prisma.BarrelWhereInput,
    customerCode: string | undefined,
    user: User,
  ): Promise<BarrelSizeCount[]> {
    // Authorization check: non-privileged users must provide customer scoping
    this.validateCustomerScopingRequired(user, customerCode, where);

    // Apply customer filter if provided
    const effectiveWhere = customerCode
      ? this.mergeCustomerCodeIntoWhere(where, customerCode)
      : where;

    const results = await this.prisma.barrel.groupBy({
      by: ["barrelSize"],
      where: effectiveWhere,
      _count: { id: true },
      orderBy: { _count: { id: "desc" } },
    });

    return results.map((r) => ({
      barrelSize: r.barrelSize || "Unknown",
      count: r._count.id,
    }));
  }

