@Injectable()
export class DatabaseProgressService {
  private readonly logger = new Logger(DatabaseProgressService.name);

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Start tracking a new batch
   */
  async startBatchProgress(
    sessionId: string,
    batchNumber: number,
    batchSize: number,
  ): Promise<string> {
    try {
      const result = await this.prisma.$queryRaw<
        { start_batch_progress: string }[]
      >`
        SELECT start_batch_progress(${sessionId}::text, ${batchNumber}::int, ${batchSize}::int) as start_batch_progress
      `;

      if (!result || result.length === 0) {
        throw new Error("Failed to start batch progress tracking");
      }

      const progressId = result[0].start_batch_progress;
      this.logger.debug(`Started batch progress tracking: ${progressId}`);
      return progressId;
    } catch (error) {
      this.logger.error("Failed to start batch progress tracking:", error);
      throw error;
    }
  }

  /**
   * Update batch progress
   */
