type Mode = "incremental" | "backfill";

function parseArgs(argv: string[]): {
  table?: string;
  mode: Mode;
  since?: Date;
  limit?: number;
  dryRun: boolean;
} {
  const args = new Map<string, string | boolean>();
  for (let i = 2; i < argv.length; i++) {
    const a = argv[i];
    if (a.startsWith("--")) {
      const [k, v] = a.split("=");
      args.set(k.replace(/^--/, ""), v ?? true);
    }
  }

  const table = (args.get("table") as string | undefined) || undefined;
  const mode = ((args.get("mode") as string | undefined) ||
    "incremental") as Mode;
  const sinceRaw = args.get("since") as string | undefined;
  const limit = args.get("limit") ? Number(args.get("limit")) : undefined;
  const dryRun = Boolean(args.get("dry-run")) || false;

  const since = sinceRaw ? new Date(sinceRaw) : undefined;
  if (since && isNaN(since.getTime())) {
    throw new Error(`Invalid --since value: ${sinceRaw}`);
  }

  return { table, mode, since, limit, dryRun };
}

