import { registerEnumType } from "@nestjs/graphql";

/**
 * Time period granularity for aggregating storage entries.
 * Determines how events are grouped by time.
 */
export enum TimePeriodGranularity {
  DAILY = "DAILY",
  WEEKLY = "WEEKLY",
  MONTHLY = "MONTHLY",
}

registerEnumType(TimePeriodGranularity, {
  name: "TimePeriodGranularity",
  description: "Time period granularity for aggregating storage entries",
});

/**
 * Maps TimePeriodGranularity to PostgreSQL DATE_TRUNC interval.
 */
export function getDateTruncInterval(
  granularity: TimePeriodGranularity,
): string {
  switch (granularity) {
    case TimePeriodGranularity.DAILY:
      return "day";
    case TimePeriodGranularity.WEEKLY:
      return "week";
    case TimePeriodGranularity.MONTHLY:
      return "month";
    default:
      return "day";
  }
}

/**
 * Maps TimePeriodGranularity to PostgreSQL interval for calculating period end.
 */
export function getPeriodEndInterval(
  granularity: TimePeriodGranularity,
): string {
  switch (granularity) {
    case TimePeriodGranularity.DAILY:
      return "1 day";
    case TimePeriodGranularity.WEEKLY:
      return "1 week";
    case TimePeriodGranularity.MONTHLY:
      return "1 month";
    default:
      return "1 day";
  }
}

